MODULE_COLORS <- c(
  black       = "#2B2B2B",
  brown       = "#9C6B00",
  yellow      = "#B7D500",
  blue        = "#1535E8",
  green       = "#3E8F4E",
  red         = "#B4334A",
  purple      = "#8A2BE2",
  magenta     = "#C75ACD",
  pink        = "#F3A6D6",
  greenyellow = "#ADFF2F",
  grey        = "#9E9E9E"
)

get_module_color <- function(module_name) {
  module_name <- as.character(module_name)

  cols <- MODULE_COLORS[module_name]

  cols[is.na(cols)] <- "#7F7F7F"

  unname(cols)
}

safe_write_csv <- function(x, file) {
  dir.create(dirname(file), recursive = TRUE, showWarnings = FALSE)
  readr::write_csv(x, file)
}

safe_file_tag <- function(x) {
  x <- as.character(x)
  x <- gsub("[^A-Za-z0-9_\\-]+", "_", x)
  x <- gsub("_+", "_", x)
  x <- gsub("^_|_$", "", x)
  x
}

clean_text_na <- function(x) {
  x <- as.character(x)
  x <- trimws(x)
  x[x %in% c("", "NA", "NaN", "NULL", "null", "N/A", "nan")] <- NA_character_
  x
}

safe_numeric <- function(x) {
  suppressWarnings(as.numeric(x))
}

ensure_column <- function(df, col, default = NA_character_) {
  if (!col %in% names(df)) {
    df[[col]] <- default
  }
  df
}

plot_hub_bar <- function(df_hubs, module_name, n_plot = 15, outdir_fig) {
  if (is.null(df_hubs) || nrow(df_hubs) == 0) return(NULL)

  module_col <- get_module_color(module_name)

  df_plot <- df_hubs %>%
    dplyr::slice(seq_len(min(n_plot, nrow(df_hubs)))) %>%
    dplyr::mutate(
      Protein_Label = dplyr::coalesce(
        Protein_Display,
        Protein_Name,
        EntrezGeneSymbol
      ),
      Protein_Label = factor(Protein_Label, levels = rev(Protein_Label))
    )

  p <- ggplot(df_plot, aes(x = Protein_Label, y = abs_kME)) +
    geom_col(fill = module_col, width = 0.8) +
    coord_flip() +
    labs(
      title = paste0("Top hubs — module ", module_name),
      x = NULL,
      y = "|kME|"
    ) +
    theme_bw(base_size = 12) +
    theme(
      plot.title = element_text(face = "bold"),
      panel.grid.major.y = element_blank(),
      panel.grid.minor = element_blank()
    )

  ggsave(
    filename = file.path(outdir_fig, paste0("top_hubs_barplot_", module_name, ".pdf")),
    plot = p,
    width = 7,
    height = 5
  )

  ggsave(
    filename = file.path(outdir_fig, paste0("top_hubs_barplot_", module_name, ".png")),
    plot = p,
    width = 7,
    height = 5,
    dpi = 300
  )

  return(p)
}

plot_enrichment_bar <- function(res, module_name, analysis_name, outdir_fig, n_show = 12) {
  if (is.null(res) || nrow(res) == 0) return(NULL)

  module_col <- get_module_color(module_name)

  top_res <- res %>%
    dplyr::arrange(p.adjust, pvalue) %>%
    dplyr::slice(seq_len(min(n_show, nrow(res)))) %>%
    dplyr::mutate(
      Description = stringr::str_wrap(Description, width = 45),
      Description = factor(Description, levels = rev(Description)),
      minus_log10_padj = -log10(pmax(p.adjust, .Machine$double.xmin))
    )

  p <- ggplot(top_res, aes(x = Description, y = minus_log10_padj)) +
    geom_col(fill = module_col, width = 0.8) +
    coord_flip() +
    labs(
      title = paste0(analysis_name, " enrichment — ", module_name),
      x = NULL,
      y = expression(-log[10]("FDR"))
    ) +
    theme_bw(base_size = 12) +
    theme(
      plot.title = element_text(face = "bold"),
      panel.grid.major.y = element_blank(),
      panel.grid.minor = element_blank()
    )

  ggsave(
    filename = file.path(outdir_fig, paste0("barplot_", analysis_name, "_", module_name, ".pdf")),
    plot = p,
    width = 8,
    height = 5.5
  )

  ggsave(
    filename = file.path(outdir_fig, paste0("barplot_", analysis_name, "_", module_name, ".png")),
    plot = p,
    width = 8,
    height = 5.5,
    dpi = 300
  )

  return(p)
}

save_enrichment_tables <- function(res, module_name, analysis_name) {
  if (is.null(res)) {
    return(NULL)
  }

  res <- as.data.frame(res)

  if (nrow(res) == 0) {
    return(NULL)
  }

  res <- res %>%
    dplyr::arrange(p.adjust, pvalue)

  safe_write_csv(
    res,
    file.path(outdir, "enrichment", analysis_name, paste0("enrichment_", analysis_name, "_", module_name, "_all_terms.csv"))
  )

  sig <- res %>%
    dplyr::filter(!is.na(p.adjust), p.adjust < enrich_sig_fdr_cutoff)

  safe_write_csv(
    sig,
    file.path(outdir, "enrichment", "significant", paste0("enrichment_", analysis_name, "_", module_name, "_FDR005.csv"))
  )

  top <- res %>%
    dplyr::slice(seq_len(min(show_terms_per_plot, nrow(res))))

  safe_write_csv(
    top,
    file.path(outdir, "enrichment", "top_terms", paste0("enrichment_", analysis_name, "_", module_name, "_top_terms.csv"))
  )

  plot_enrichment_bar(
    res = top,
    module_name = module_name,
    analysis_name = analysis_name,
    outdir_fig = file.path(outdir, "figures", "enrichment"),
    n_show = show_terms_per_plot
  )

  res
}

make_enrich_count <- function(res) {
  if (is.null(res) || nrow(res) == 0) {
    return(tibble::tibble(
      n_terms_total = 0,
      n_terms_fdr_0_05 = 0,
      n_terms_fdr_0_10 = 0,
      min_FDR = NA_real_,
      top_term = NA_character_
    ))
  }

  res <- as.data.frame(res) %>% dplyr::arrange(p.adjust, pvalue)

  tibble::tibble(
    n_terms_total = nrow(res),
    n_terms_fdr_0_05 = sum(!is.na(res$p.adjust) & res$p.adjust < enrich_sig_fdr_cutoff),
    n_terms_fdr_0_10 = sum(!is.na(res$p.adjust) & res$p.adjust < enrich_suggestive_fdr_cutoff),
    min_FDR = suppressWarnings(min(res$p.adjust, na.rm = TRUE)),
    top_term = ifelse(nrow(res) > 0, as.character(res$Description[[1]]), NA_character_)
  ) %>%
    dplyr::mutate(
      min_FDR = ifelse(is.infinite(min_FDR), NA_real_, min_FDR)
    )
}

