###############################################################################
# 7) kME / MODULE MEMBERSHIP
###############################################################################

kME_mat <- WGCNA::signedKME(
  datExpr = datExpr_clean,
  datME = mergedMEs,
  exprWeights = NULL,
  MEWeights = NULL,
  outputColumnName = "kME",
  corFnc = "cor",
  corOptions = "use = 'pairwise.complete.obs'"
)

kME_tbl <- tibble::tibble(
  EntrezGeneSymbol = rownames(kME_mat)
) %>%
  dplyr::bind_cols(as.data.frame(kME_mat))

n_samples_kme <- nrow(datExpr_clean)

kME_long <- kME_tbl %>%
  tidyr::pivot_longer(
    cols = starts_with("kME"),
    names_to = "ME_col",
    values_to = "kME"
  ) %>%
  dplyr::mutate(
    Module_from_ME = gsub("^kME", "", ME_col),
    abs_kME = abs(kME)
  )

gene_module_small <- gene_module_assignment_tbl %>%
  dplyr::select(
    EntrezGeneSymbol,
    Module,
    Protein_Name,
    Protein_Display,
    Representative_AptName,
    AptName,
    SeqId,
    TargetFullName,
    Target,
    UniProt,
    EntrezGeneID,
    N_genes,
    Prop_total
  ) %>%
  dplyr::distinct()

kME_annot <- kME_long %>%
  dplyr::left_join(gene_module_small, by = "EntrezGeneSymbol") %>%
  dplyr::mutate(
    is_assigned_module = Module == Module_from_ME
  )

kME_assigned <- kME_annot %>%
  dplyr::filter(is_assigned_module) %>%
  dplyr::mutate(
    t_stat = kME * sqrt((n_samples_kme - 2) / pmax(1e-12, 1 - kME^2)),
    p_value = 2 * stats::pt(-abs(t_stat), df = n_samples_kme - 2)
  ) %>%
  dplyr::group_by(Module) %>%
  dplyr::mutate(
    FDR_within_module = p.adjust(p_value, method = "BH")
  ) %>%
  dplyr::ungroup() %>%
  dplyr::arrange(Module, dplyr::desc(abs_kME), p_value)

safe_write_csv(
  kME_tbl,
  file.path(outdir, "tables", "full_kME_table_wide.csv")
)

safe_write_csv(
  kME_assigned,
  file.path(outdir, "tables", "full_kME_assigned_module_long.csv")
)

