hub_summary <- kME_assigned %>%
  dplyr::group_by(Module) %>%
  dplyr::summarise(
    n_genes = dplyr::n(),
    mean_abs_kME = mean(abs_kME, na.rm = TRUE),
    median_abs_kME = median(abs_kME, na.rm = TRUE),
    max_abs_kME = max(abs_kME, na.rm = TRUE),
    n_hubs_abs_kME_ge_0_8 = sum(abs_kME >= 0.80, na.rm = TRUE),
    n_hubs_abs_kME_ge_0_7 = sum(abs_kME >= 0.70, na.rm = TRUE),
    .groups = "drop"
  ) %>%
  dplyr::arrange(dplyr::desc(max_abs_kME))

safe_write_csv(
