  file.path(outdir, "tables", "module_hub_summary.csv")
)

###############################################################################
# 9) TOP HUBS BY MODULE
###############################################################################

hub_tables <- list()

for (mod in modules_of_interest) {

  df_mod <- kME_assigned %>%
    dplyr::filter(Module == mod) %>%
    dplyr::arrange(dplyr::desc(abs_kME), p_value) %>%
    dplyr::mutate(
      hub_rank = dplyr::row_number()
    )

  if (nrow(df_mod) == 0) {
    message("Módulo sin genes asignados en kME_assigned: ", mod)
    next
  }

  n_top <- min(top_hubs_per_module, nrow(df_mod))
  top_mod <- head(df_mod, n_top)

  hub_tables[[mod]] <- top_mod

  safe_write_csv(
    df_mod,
    file.path(outdir, "hubs", paste0("all_hubs_ranked_", mod, ".csv"))
  )

  safe_write_csv(
    top_mod,
    file.path(outdir, "hubs", paste0("top_hubs_", mod, ".csv"))
  )

  plot_hub_bar(
    df_hubs = top_mod,
    module_name = mod,
    n_plot = top_plot_hubs,
    outdir_fig = file.path(outdir, "figures", "hubs")
  )
}

top_hubs_all_modules <- dplyr::bind_rows(hub_tables)

