###############################################################################
# 10) GENE ID MAPPING FOR ENRICHMENT
###############################################################################

gene_universe <- gene_module_assignment_tbl %>%
  dplyr::transmute(
    EntrezGeneSymbol = clean_text_na(EntrezGeneSymbol),
    EntrezGeneID = safe_numeric(EntrezGeneID)
  ) %>%
  dplyr::filter(
    !is.na(EntrezGeneSymbol),
    EntrezGeneSymbol != ""
  ) %>%
  dplyr::distinct()

symbol_to_entrez <- tryCatch(
  clusterProfiler::bitr(
    gene_universe$EntrezGeneSymbol,
    fromType = "SYMBOL",
    toType = "ENTREZID",
    OrgDb = org.Hs.eg.db
  ),
  error = function(e) {
    message("SYMBOL -> ENTREZID mapping failed: ", e$message)
    NULL
  }
)

if (is.null(symbol_to_entrez) || nrow(symbol_to_entrez) == 0) {

  if (all(is.na(gene_universe$EntrezGeneID))) {
    stop("No se pudo mapear SYMBOL -> ENTREZID y EntrezGeneID no está disponible.", call. = FALSE)
  }

  gene_universe_mapped <- gene_universe %>%
    dplyr::mutate(
      ENTREZID_final = as.character(EntrezGeneID)
    ) %>%
    dplyr::filter(!is.na(ENTREZID_final), ENTREZID_final != "") %>%
    dplyr::distinct(EntrezGeneSymbol, .keep_all = TRUE)

} else {

  gene_universe_mapped <- gene_universe %>%
    dplyr::left_join(
      symbol_to_entrez %>%
        dplyr::rename(
          EntrezGeneSymbol = SYMBOL,
          ENTREZID_map = ENTREZID
        ),
      by = "EntrezGeneSymbol"
    ) %>%
    dplyr::mutate(
      ENTREZID_final = dplyr::coalesce(
        as.character(EntrezGeneID),
        ENTREZID_map
      )
    ) %>%
    dplyr::filter(
      !is.na(ENTREZID_final),
      ENTREZID_final != ""
    ) %>%
    dplyr::distinct(EntrezGeneSymbol, .keep_all = TRUE)
}

background_entrez <- unique(gene_universe_mapped$ENTREZID_final)

if (length(background_entrez) < min_genes_for_enrichment) {
  stop("El universo de fondo mapeado para enrichment es demasiado pequeño.", call. = FALSE)
}

safe_write_csv(
  gene_universe_mapped,
  file.path(outdir, "tables", "gene_universe_symbol_to_entrez.csv")
)

###############################################################################
# 11) ENRICHMENT BY MODULE
###############################################################################

enrichment_summary <- list()
enrichment_errors <- list()

for (mod in modules_of_interest) {

  cat("\n============================\n")
  cat("Procesando módulo:", mod, "\n")
  cat("============================\n")

  module_genes <- gene_module_assignment_tbl %>%
    dplyr::filter(Module == mod) %>%
    dplyr::transmute(
      EntrezGeneSymbol = clean_text_na(EntrezGeneSymbol),
      Protein_Name = Protein_Name
    ) %>%
    dplyr::filter(
      !is.na(EntrezGeneSymbol),
      EntrezGeneSymbol != ""
    ) %>%
    dplyr::distinct()

  module_genes_mapped <- module_genes %>%
    dplyr::left_join(
      gene_universe_mapped %>%
        dplyr::select(EntrezGeneSymbol, ENTREZID_final),
      by = "EntrezGeneSymbol"
    ) %>%
    dplyr::filter(
      !is.na(ENTREZID_final),
      ENTREZID_final != ""
    ) %>%
    dplyr::distinct(EntrezGeneSymbol, .keep_all = TRUE)

  safe_write_csv(
    module_genes_mapped,
    file.path(outdir, "tables", paste0("genes_for_enrichment_", mod, ".csv"))
  )

  module_entrez <- unique(module_genes_mapped$ENTREZID_final)

  enrich_info <- tibble::tibble(
    Module = mod,
    n_symbols = nrow(module_genes),
    n_mapped_entrez = length(module_entrez),
    n_background = length(background_entrez)
  )

  safe_write_csv(
    enrich_info,
    file.path(outdir, "tables", paste0("enrichment_input_summary_", mod, ".csv"))
  )

  if (length(module_entrez) < min_genes_for_enrichment) {
    message("Módulo ", mod, " omitido en enrichment por pocos genes mapeados.")

    enrichment_summary[[mod]] <- tibble::tibble(
      Module = mod,
      n_symbols = nrow(module_genes),
      n_mapped_entrez = length(module_entrez),
      n_background = length(background_entrez),
      GO_BP_terms = 0,
      GO_BP_terms_fdr010 = 0,
      GO_BP_terms_total = 0,
      GO_BP_min_FDR = NA_real_,
      GO_BP_top_term = NA_character_,
      KEGG_terms = 0,
      KEGG_terms_fdr010 = 0,
      KEGG_terms_total = 0,
      KEGG_min_FDR = NA_real_,
      KEGG_top_term = NA_character_,
      Reactome_terms = 0,
      Reactome_terms_fdr010 = 0,
      Reactome_terms_total = 0,
      Reactome_min_FDR = NA_real_,
      Reactome_top_term = NA_character_
    )

    next
  }

  # -------------------------------------------------------------------------
  # GO Biological Process
  # -------------------------------------------------------------------------

  ego_bp <- tryCatch(
    clusterProfiler::enrichGO(
      gene = module_entrez,
      universe = background_entrez,
      OrgDb = org.Hs.eg.db,
      keyType = "ENTREZID",
      ont = "BP",
      pAdjustMethod = "BH",
      pvalueCutoff = enrich_retrieve_p_cutoff,
      qvalueCutoff = enrich_retrieve_q_cutoff,
      readable = TRUE
    ),
    error = function(e) {
      enrichment_errors[[paste(mod, "GO_BP", sep = "_")]] <<- tibble::tibble(
        Module = mod,
        Library = "GO_BP",
        Error = e$message
      )
      message("GO BP enrichment failed for module ", mod, ": ", e$message)
      NULL
    }
  )

  res_go <- save_enrichment_tables(
    res = ego_bp,
    module_name = mod,
    analysis_name = "GO_BP"
  )

  count_go <- make_enrich_count(res_go)

  # -------------------------------------------------------------------------
  # KEGG
  # -------------------------------------------------------------------------

  ekegg <- tryCatch(
    clusterProfiler::enrichKEGG(
      gene = module_entrez,
      universe = background_entrez,
      organism = "hsa",
      pAdjustMethod = "BH",
      pvalueCutoff = enrich_retrieve_p_cutoff,
      qvalueCutoff = enrich_retrieve_q_cutoff
    ),
    error = function(e) {
      enrichment_errors[[paste(mod, "KEGG", sep = "_")]] <<- tibble::tibble(
        Module = mod,
        Library = "KEGG",
        Error = e$message
      )
      message("KEGG enrichment failed for module ", mod, ": ", e$message)
      NULL
    }
  )

  res_kegg <- save_enrichment_tables(
    res = ekegg,
    module_name = mod,
    analysis_name = "KEGG"
  )

  count_kegg <- make_enrich_count(res_kegg)

  # -------------------------------------------------------------------------
  # Reactome
  # -------------------------------------------------------------------------

  ereact <- tryCatch(
    ReactomePA::enrichPathway(
      gene = module_entrez,
      universe = background_entrez,
      organism = "human",
      pvalueCutoff = enrich_retrieve_p_cutoff,
      pAdjustMethod = "BH",
      qvalueCutoff = enrich_retrieve_q_cutoff,
      readable = TRUE
    ),
    error = function(e) {
      enrichment_errors[[paste(mod, "Reactome", sep = "_")]] <<- tibble::tibble(
        Module = mod,
        Library = "Reactome",
        Error = e$message
      )
      message("Reactome enrichment failed for module ", mod, ": ", e$message)
      NULL
    }
  )

  res_react <- save_enrichment_tables(
    res = ereact,
    module_name = mod,
    analysis_name = "Reactome"
  )

  count_react <- make_enrich_count(res_react)

  enrichment_summary[[mod]] <- tibble::tibble(
    Module = mod,
    n_symbols = nrow(module_genes),
    n_mapped_entrez = length(module_entrez),
    n_background = length(background_entrez),

    GO_BP_terms = count_go$n_terms_fdr_0_05,
    GO_BP_terms_fdr010 = count_go$n_terms_fdr_0_10,
    GO_BP_terms_total = count_go$n_terms_total,
    GO_BP_min_FDR = count_go$min_FDR,
    GO_BP_top_term = count_go$top_term,

    KEGG_terms = count_kegg$n_terms_fdr_0_05,
    KEGG_terms_fdr010 = count_kegg$n_terms_fdr_0_10,
    KEGG_terms_total = count_kegg$n_terms_total,
    KEGG_min_FDR = count_kegg$min_FDR,
    KEGG_top_term = count_kegg$top_term,

    Reactome_terms = count_react$n_terms_fdr_0_05,
    Reactome_terms_fdr010 = count_react$n_terms_fdr_0_10,
    Reactome_terms_total = count_react$n_terms_total,
    Reactome_min_FDR = count_react$min_FDR,
    Reactome_top_term = count_react$top_term
  )
}

enrichment_summary_tbl <- dplyr::bind_rows(enrichment_summary)

safe_write_csv(
  enrichment_summary_tbl,
  file.path(outdir, "tables", "enrichment_summary_by_module.csv")
)

if (length(enrichment_errors) > 0) {
  enrichment_errors_tbl <- dplyr::bind_rows(enrichment_errors)
} else {
  enrichment_errors_tbl <- tibble::tibble(
    Module = character(),
    Library = character(),
    Error = character()
  )
}

safe_write_csv(
  enrichment_errors_tbl,
  file.path(outdir, "tables", "enrichment_errors_by_module.csv")
)

###############################################################################
# 12) OPTIONAL NETWORK TABLES
###############################################################################

for (mod in modules_of_interest) {

  if (!mod %in% names(hub_tables)) next

  node_tbl <- hub_tables[[mod]] %>%
    dplyr::mutate(
      node = EntrezGeneSymbol,
      label = dplyr::coalesce(
        Protein_Display,
        Protein_Name,
        EntrezGeneSymbol
      ),
      module = Module,
      module_color = get_module_color(Module),
      kME = kME,
      abs_kME = abs_kME,
      hub_rank = hub_rank
    ) %>%
    dplyr::select(
      node,
      label,
      module,
      module_color,
      kME,
      abs_kME,
      hub_rank,
      dplyr::everything()
    )

  safe_write_csv(
    node_tbl,
    file.path(outdir, "network_optional", paste0("nodes_top_hubs_", mod, ".csv"))
  )
}

###############################################################################
# 13) FINAL SUMMARY
###############################################################################

final_summary <- tibble::tibble(
  metric = c(
    "base_dir",
    "core_dir",
    "outdir",
    "wgcna_input_level",
    "n_samples_used_for_kME",
    "n_genes_in_datExpr_clean",
    "n_module_eigengenes",
    "n_prioritized_modules",
    "top_hubs_per_module_exported",
    "min_genes_for_enrichment",
    "n_background_entrez",
    "enrichment_retrieve_p_cutoff",
    "enrichment_retrieve_q_cutoff",
    "enrichment_sig_fdr_cutoff",
    "enrichment_suggestive_fdr_cutoff"
  ),
  value = c(
    base_dir,
    core_dir,
    outdir,
    "GENE-COLLAPSED, not aptamer-level",
    as.character(nrow(datExpr_clean)),
    as.character(ncol(datExpr_clean)),
    as.character(ncol(mergedMEs)),
    as.character(length(modules_of_interest)),
    as.character(top_hubs_per_module),
    as.character(min_genes_for_enrichment),
    as.character(length(background_entrez)),
    as.character(enrich_retrieve_p_cutoff),
    as.character(enrich_retrieve_q_cutoff),
    as.character(enrich_sig_fdr_cutoff),
    as.character(enrich_suggestive_fdr_cutoff)
  )
)

safe_write_csv(
  final_summary,
  file.path(outdir, "tables", "script3_final_summary.csv")
)

###############################################################################
# 14) SAVE WORKSPACE
###############################################################################

save(
  datExpr_clean,
  mergedMEs,
  gene_module_assignment_tbl,
  kME_tbl,
  kME_assigned,
  hub_summary,
  hub_tables,
  gene_universe_mapped,
  background_entrez,
  enrichment_summary_tbl,
  enrichment_errors_tbl,
  final_summary,
  file = file.path(outdir, "workspace", "script3_module_biology_workspace.RData")
)

writeLines(
  capture.output(utils::sessionInfo()),
  con = file.path(outdir, "sessionInfo.txt")
)

