cat("Directorio principal de salida:\n", outdir, "\n")
cat("Input level: GENE-COLLAPSED, not aptamer-level.\n")
cat("\nArchivos clave:\n")
cat("- tables/full_kME_assigned_module_long.csv\n")
cat("- tables/module_hub_summary.csv\n")
