cat("- enrichment/GO_BP/*_all_terms.csv\n")
cat("- enrichment/KEGG/*_all_terms.csv\n")
cat("- enrichment/Reactome/*_all_terms.csv\n")
cat("- enrichment/significant/*_FDR005.csv\n")
cat("- enrichment/top_terms/*_top_terms.csv\n")
cat("- figures/hubs/*.pdf/png\n")
cat("- figures/enrichment/*.pdf/png\n")

